import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"포켓몬스터 레전즈 아르세우스","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/games/포켓몬스터-레전즈-아르세우스.md","filePath":"outta-space/knowledge/games/포켓몬스터-레전즈-아르세우스.md"}'),_={name:"outta-space/knowledge/games/포켓몬스터-레전즈-아르세우스.md"};function n(l,a,s,i,d,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="포켓몬스터-레전즈-아르세우스" tabindex="-1">포켓몬스터 레전즈 아르세우스 <a class="header-anchor" href="#포켓몬스터-레전즈-아르세우스" aria-label="Permalink to &quot;포켓몬스터 레전즈 아르세우스&quot;">​</a></h1><h2 id="_1-핵심-플레이-경험" tabindex="-1">1. 핵심 플레이 경험 <a class="header-anchor" href="#_1-핵심-플레이-경험" aria-label="Permalink to &quot;1. 핵심 플레이 경험&quot;">​</a></h2><p>기존의 포켓몬스터와 달리, 배틀 위주가 아닌 생존 및 포획을 위주로 한 게임이다. 잠입 액션을 하는 듯한 느낌도 난다.</p><h2 id="_2-조작감과-전투-시스템" tabindex="-1">2. 조작감과 전투 / 시스템 <a class="header-anchor" href="#_2-조작감과-전투-시스템" aria-label="Permalink to &quot;2. 조작감과 전투 / 시스템&quot;">​</a></h2><p>시스템. 일단 파우치 열기 불편해.</p><p>전투. 내가 먹이를 안 써서 그런가 좀 무섭고 불합리해.</p><p>조작감은 라이딩 포켓몬의 방향 전환을 제외하면 깔끔합니다.</p><h2 id="_3-스토리와-캐릭터" tabindex="-1">3. 스토리와 캐릭터 <a class="header-anchor" href="#_3-스토리와-캐릭터" aria-label="Permalink to &quot;3. 스토리와 캐릭터&quot;">​</a></h2><p>캐릭터? 역시 포켓몬 답게 디자인은 잘 뽑아. 근데 다들 착해가지고 매력은 모르겠어.</p><p>스토리? 그냥 우두머리 잡는 거 밖에 없어서 잘 모르겠어. 아르세우스는 사이코패스가 맞고...</p><h2 id="_4-그래픽-사운드-연출" tabindex="-1">4. 그래픽, 사운드, 연출 <a class="header-anchor" href="#_4-그래픽-사운드-연출" aria-label="Permalink to &quot;4. 그래픽, 사운드, 연출&quot;">​</a></h2><p>해당 게임이 나왔을 때를 기준으로 하면 포켓몬 게임 기준으로 최상의 그래픽이 나온 것이 맞다. 동시대 게임과 비교해서는 좀 그렇지만. 제노블과 비교하면 좀 심할거다.</p><p>사운드는 신오지방 특유의 사운드들을 고풍적으로 어레인지 해서 ost, 효과음에 모두 활용했다. 특히 라이딩 포켓몬</p><h2 id="_5-몰입도와-재플레이-가치" tabindex="-1">5. 몰입도와 재플레이 가치 <a class="header-anchor" href="#_5-몰입도와-재플레이-가치" aria-label="Permalink to &quot;5. 몰입도와 재플레이 가치&quot;">​</a></h2><p>포켓몬을 사랑한다면 당연히 몰입도 가득하게 할 수 있다. 특히 잠입 액션을 할 때가 몰입도 넘친다.</p>',15)])])}const u=e(_,[["render",n]]);export{c as __pageData,u as default};
